package buildpack

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/buildpack"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type BuildPackProxy struct {
	buildpack.UnimplementedBuildPackServer
	client buildpack.BuildPackClient
}

func init() {
	proxyutil.Register(&buildpack.BuildPack_ServiceDesc, NewBuildPackProxy)
}
func NewBuildPackProxy(cc grpc.ClientConnInterface) buildpack.BuildPackServer {
	return &BuildPackProxy{client: buildpack.NewBuildPackClient(cc)}
}
func (p *BuildPackProxy) Compile(ctx context.Context, in *buildpack.CompileParams) (*buildpack.CompileResponse, error) {
	return proxyutil.ProxyMethod[buildpack.CompileParams, buildpack.CompileResponse](p.client.Compile)(ctx, in)
}
